static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    VanillaRnnHiddenCustomTilingData tiling;
    const gert::ShapeInfo *x_shape_info = context->GetInputShape(0);
    const gert::Shape *x_shape = &x_shape_info->GetOriginShape();
    const gert::ShapeInfo *h0_shape_info = context->GetInputShape(1);
    const gert::Shape *h0_shape = &h0_shape_info->GetOriginShape();
    const gert::ShapeInfo *w_h2o_shape_info = context->GetInputShape(4);
    const gert::Shape *w_h2o_shape = &w_h2o_shape_info->GetOriginShape();

    // x shape: (T, B, I)
    uint32_t T = static_cast<uint32_t>(x_shape->GetDim(0));
    uint32_t B = static_cast<uint32_t>(x_shape->GetDim(1));
    uint32_t I = static_cast<uint32_t>(x_shape->GetDim(2));
    // h0 shape: (B, H)
    uint32_t H = static_cast<uint32_t>(h0_shape->GetDim(1));
    // w_h2o shape: (O, H)
    uint32_t O = static_cast<uint32_t>(w_h2o_shape->GetDim(0));
    uint32_t K = I + H;

    uint32_t totalLength = T * B * O;
    // tileLength: input slice per time step for one batch (B*I) enough for all needed buffers
    uint32_t tileLength = B * I;  // fit in UB (8192 floats = 32KB)
    // blockDim: use batch size, cap to available cores
    uint32_t blockDim = B;
    if (blockDim < 1) blockDim = 1;
    if (blockDim > 24) blockDim = 24;  // typical limit on 910B

    context->SetBlockDim(blockDim);

    tiling.set_totalLength(totalLength);
    tiling.set_tileLength(tileLength);
    tiling.set_blockDim(blockDim);
    tiling.set_T(T);
    tiling.set_B(B);
    tiling.set_I(I);
    tiling.set_H(H);
    tiling.set_O(O);
    tiling.set_K(K);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

} // namespace optiling

